const body = $input.first().json.body || $input.first().json;
const title = body.title || '';
const description = body.description || '';
const url = body.url || '';
const extra = body.extra_text || body.content || '';

if (!title && !description && !extra) {
  throw new Error('Necesitas title, description o extra_text');
}

const systemPrompt = `Eres el gestor de contenido de Jorge Lorenzo, ex-piloto MotoGP reconvertido en referente de liderazgo, alto rendimiento y mentalidad ganadora. Genera posts para redes sociales basados en el contenido recibido. REGLAS: Conecta siempre con liderazgo y alto rendimiento. Usa perspectiva de alguien que ha competido al maximo nivel. NUNCA uses comillas dobles dentro de los textos. Devuelve SOLO JSON valido en una sola linea.`;

const userPrompt = `CONTENIDO:\nTitulo: ${title}\nDescripcion: ${description}\nURL: ${url}\nTexto extra: ${extra}\n\nDevuelve exactamente este JSON:\n{"topic":"tema en 5 palabras","linkedin_post":"post completo 300-600 chars con leccion liderazgo bullets y hashtags","linkedin_score":8,"instagram_post":"post 100-150 chars hook emojis hashtags","instagram_image_prompt":"image description in english","instagram_score":7,"twitter_post":"tweet max 280 chars hook fuerte","twitter_score":7,"tiktok_script":"guion 60s: hook 0-3s desarrollo CTA","tiktok_score":6,"hashtags":["tag1","tag2","tag3"]}`;

return [{ json: { systemPrompt, userPrompt, title, description, url, extra } }];

const response = $input.first().json;
const content = response.choices?.[0]?.message?.content || '';

let data;
try {
  data = JSON.parse(content);
} catch(e) {
  throw new Error('JSON invalido: ' + content.substring(0, 300));
}

const prev = $('Construir Prompt').first().json;

return [{ json: {
  date: new Date().toISOString().split('T')[0],
  topic: data.topic || prev.title,
  source_url: prev.url || null,
  linkedin_post: data.linkedin_post || null,
  linkedin_score: data.linkedin_score || null,
  instagram_post: data.instagram_post || null,
  instagram_image_prompt: data.instagram_image_prompt || null,
  instagram_score: data.instagram_score || null,
  twitter_post: data.twitter_post || null,
  twitter_score: data.twitter_score || null,
  tiktok_script: data.tiktok_script || null,
  tiktok_score: data.tiktok_score || null,
  hashtags: data.hashtags || [],
  status: 'pending_review'
} }];
